1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	
5	const COMPONENT_BASE_PREMIUM = 25;
6	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
7	const COMPONENT_BLOCK_SIZE = 3;
8	const COMPONENT_BLOCK_PREMIUM = 60;
9	
10	const NON_COMPONENT_BASE_PREMIUM: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	};
16	
17	const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);
18	
19	const basePremiumFor = (type: string): number =>
20	  isComponent(type) ? COMPONENT_BASE_PREMIUM : NON_COMPONENT_BASE_PREMIUM[type];
21	
22	type Item = { type: string; cursed?: boolean };
23	type QuoteStep = { op: "quote"; items: Item[] };
24	type Step = QuoteStep;
25	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
26	
27	const groupedBasePremium = (type: string, count: number): number => {
28	  if (isComponent(type) && count === COMPONENT_BLOCK_SIZE) {
29	    return COMPONENT_BLOCK_PREMIUM;
30	  }
31	  return count * basePremiumFor(type);
32	};
33	
34	const countByType = (items: Item[]): Map<string, number> => {
35	  const counts = new Map<string, number>();
36	  for (const item of items) {
37	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
38	  }
39	  return counts;
40	};
41	
42	const sumBasePremiums = (items: Item[]): number =>
43	  Array.from(countByType(items)).reduce(
44	    (total, [type, count]) => total + groupedBasePremium(type, count),
45	    0,
46	  );
47	
48	const itemSurcharges = (items: Item[]): number =>
49	  items.reduce(
50	    (sum, item) =>
51	      sum + (item.cursed ? basePremiumFor(item.type) * CURSE_SURCHARGE_RATE : 0),
52	    0,
53	  );
54	
55	const quotePremium = (items: Item[]): number => {
56	  const basePremium = sumBasePremiums(items);
57	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
58	  const insurancePremium = Math.ceil(
59	    basePremium + itemSurcharges(items) + firstInsuranceSurcharge,
60	  );
61	  return insurancePremium + PROCESSING_FEE;
62	};
63	
64	const runStep = (step: Step) => ({ premium: quotePremium(step.items) });
65	
66	export const runScenario = (scenario: Scenario): unknown => ({
67	  results: scenario.steps.map(runStep),
68	});
